func TestGettersOcrVendorAdditionalData(t *testing.T) {
	t.Run("GetWeb", func(t *testing.T) {
		t.Parallel()
		// Arrange
		obj := &OcrVendorAdditionalData{}
		var expected *string
		obj.Web = expected

		// Act & Assert
		assert.Equal(t, expected, obj.GetWeb(), "getter should return the property value")
	})

	t.Run("GetWeb_NilValue", func(t *testing.T) {
		t.Parallel()
		// Arrange
		obj := &OcrVendorAdditionalData{}
		obj.Web = nil

		// Act & Assert
		assert.Nil(t, obj.GetWeb(), "getter should return nil when property is nil")
	})

	t.Run("GetWeb_NilReceiver", func(t *testing.T) {
		t.Parallel()
		var obj *OcrVendorAdditionalData
		// Should not panic - getters should handle nil receiver gracefully
		defer func() {
			if r := recover(); r != nil {
				t.Errorf("Getter panicked on nil receiver: %v", r)
			}
		}()
		_ = obj.GetWeb() // Should return zero value
	})

}

